const startScreen = document.getElementById('start-screen');
const quizScreen = document.getElementById('quiz-screen');
const sideScreen = document.getElementById('side-screen');
const certScreen = document.getElementById('certificate-screen');
const homeIcon = document.getElementById('home-icon');
const restartBtn = document.getElementById('restart-quiz');
const prevBtn = document.getElementById('prev-question');
const nextBtn = document.getElementById('next-question');
const explanationTrigger = document.getElementById('explanation-trigger');
const questionTextEl = document.getElementById('question-text');
const optionsList = document.getElementById('options-list');
const feedbackMsg = document.getElementById('feedback-msg');
const qTypeLabel = document.getElementById('q-type-label');
const scoreValue = document.getElementById('score-value');
const questionCounter = document.getElementById('question-counter');
const progressFill = document.getElementById('progress-fill');
const answeredCounter = document.getElementById('answered-counter');
const correctCounter = document.getElementById('correct-counter');
const quizTitle = document.getElementById('quiz-title');
const studentFullname = document.getElementById('student-fullname');
const downloadCertBtn = document.getElementById('download-certificate-btn');
const startTotal = document.getElementById('start-total-questions');

let current = 0, score = 0, answered = false;
let selectedExam = exams.web;
let questions = selectedExam.questions;
let userAnswers = Array(questions.length).fill(null);
let autoTimeout = null;

if (sideScreen) sideScreen.style.display = 'none';

function animateNumber(el, start, end) {
  if (!el) return;
  const range = Math.abs(end - start);
  if (range === 0) return;
  const step = range > 100 ? Math.ceil(range / 20) : 1;
  let cur = start;
  const timer = setInterval(() => {
    cur += (end > start ? step : -step);
    if ((end > start && cur >= end) || (end < start && cur <= end)) { cur = end; clearInterval(timer); }
    el.textContent = cur;
    el.classList.add('updated');
    setTimeout(() => el.classList.remove('updated'), 150);
  }, 20);
}

function renderQuestion() {
  if (autoTimeout) clearTimeout(autoTimeout);
  const item = questions[current];
  const saved = userAnswers[current];
  answered = saved !== null;
  feedbackMsg.textContent = '';
  feedbackMsg.className = 'feedback-msg';
  nextBtn.disabled = !answered;
  prevBtn.disabled = (current === 0);
  nextBtn.textContent = (current === questions.length - 1) ? 'عرض النتيجة' : 'التالي';
  questionTextEl.textContent = item.text;
  qTypeLabel.textContent = item.type;
  questionCounter.textContent = `السؤال ${current + 1} من ${questions.length}`;
  scoreValue.textContent = score;
  const perc = Math.round((userAnswers.filter(a => a !== null).length / questions.length) * 100);
  progressFill.style.width = `${perc}%`;
  answeredCounter.textContent = userAnswers.filter(a => a !== null).length;
  correctCounter.textContent = score;
  optionsList.innerHTML = '';
  item.answers.forEach(ans => {
    const btn = document.createElement('button');
    btn.className = 'option-btn';
    btn.textContent = ans;
    btn.addEventListener('click', () => lockAnswer(ans));
    optionsList.appendChild(btn);
  });
  hideExplanation();
  if (answered) showSavedAnswer(saved);
}

function lockAnswer(selected) {
  if (answered) return;
  const item = questions[current];
  const btns = [...document.querySelectorAll('.option-btn')];
  const isCorrect = (selected === item.correct);
  answered = true;
  userAnswers[current] = selected;
  if (isCorrect) {
    score++;
    feedbackMsg.textContent = 'إجابة صحيحة!';
    feedbackMsg.classList.add('good');
  } else {
    feedbackMsg.textContent = `خطأ. الإجابة الصحيحة: ${item.correct}`;
    feedbackMsg.classList.add('bad');
  }
  btns.forEach(btn => {
    btn.disabled = true;
    if (btn.textContent === item.correct) btn.classList.add('correct');
    else if (btn.textContent === selected) btn.classList.add('wrong');
  });
  scoreValue.textContent = score;
  answeredCounter.textContent = userAnswers.filter(a => a !== null).length;
  correctCounter.textContent = score;
  const perc = Math.round((userAnswers.filter(a => a !== null).length / questions.length) * 100);
  progressFill.style.width = `${perc}%`;
  nextBtn.disabled = false;
  animateNumber(scoreValue, score-1, score);
  animateNumber(correctCounter, score-1, score);
  if (autoTimeout) clearTimeout(autoTimeout);
  autoTimeout = setTimeout(() => {
    if (current < questions.length - 1) { current++; renderQuestion(); }
    else { showFinalResult(); }
  }, 800);
}

function showSavedAnswer(saved) {
  const item = questions[current];
  const btns = [...document.querySelectorAll('.option-btn')];
  const isCorrect = (saved === item.correct);
  feedbackMsg.textContent = isCorrect ? 'صحيح' : `خطأ. الصواب: ${item.correct}`;
  feedbackMsg.classList.add(isCorrect ? 'good' : 'bad');
  btns.forEach(btn => {
    btn.disabled = true;
    if (btn.textContent === item.correct) btn.classList.add('correct');
    else if (btn.textContent === saved) btn.classList.add('wrong');
  });
}

function showFinalResult() {
  const percentage = Math.round((score / questions.length) * 100);
  const wrongList = [];
  for (let i=0; i<questions.length; i++) {
    if (userAnswers[i] && userAnswers[i] !== questions[i].correct) {
      wrongList.push({ num: i+1, text: questions[i].text, user: userAnswers[i], correct: questions[i].correct, hint: questions[i].hint, ref: questions[i].reference });
    }
  }
  quizScreen.classList.add('hidden');
  if (sideScreen) sideScreen.style.display = 'none';
  let rp = document.getElementById('results-panel');
  if (!rp) { rp = document.createElement('div'); rp.id = 'results-panel'; rp.className = 'results-panel'; document.querySelector('.app-container').appendChild(rp); }
  rp.innerHTML = `<div class="results-header"><div class="badge">النتيجة النهائية</div><div class="results-percent">${percentage}%</div><p>${score} من ${questions.length} إجابات صحيحة</p><button id="retryBtn" class="btn-primary" style="margin-top:0.5rem;">⟳ إعادة المحاولة</button><button id="homeFromResults" class="btn-secondary" style="margin-top:0.5rem;">الرئيسية</button></div>${wrongList.length === 0 ? '<p style="text-align:center; color:#10b981;">ممتاز! لا توجد أخطاء.</p>' : `<h4>الأخطاء (${wrongList.length})</h4><div class="wrong-list">` + wrongList.map(w => `<div class="wrong-item"><strong>${w.num}.</strong> ${w.text}<br><div class="wrong-details">إجابتك: <span style="color:#ef4444;">${w.user}</span> | الصواب: <span style="color:#10b981;">${w.correct}</span></div><div class="wrong-hint">تلميح: ${w.hint}</div><div class="wrong-ref">مرجع: ${w.ref}</div></div>`).join('') + `</div>`}`;
  rp.style.display = 'block';
  document.getElementById('retryBtn').onclick = () => { rp.style.display = 'none'; startExam(Object.keys(exams).find(k => exams[k] === selectedExam)); };
  document.getElementById('homeFromResults').onclick = () => { rp.style.display = 'none'; startScreen.classList.remove('hidden'); quizScreen.classList.add('hidden'); if (sideScreen) sideScreen.style.display = 'none'; certScreen.classList.add('hidden'); };
  if (percentage >= 90 && selectedExam.certificateLabel) certScreen.classList.remove('hidden');
  else certScreen.classList.add('hidden');
}

function startExam(examKey) {
  if (autoTimeout) clearTimeout(autoTimeout);
  if (!exams[examKey]) { alert('الامتحان غير متوفر'); return; }
  selectedExam = exams[examKey];
  questions = selectedExam.questions;
  userAnswers = Array(questions.length).fill(null);
  current = 0; score = 0;
  quizTitle.textContent = selectedExam.title;
  certScreen.classList.add('hidden');
  studentFullname.value = '';
  startScreen.classList.add('hidden');
  quizScreen.classList.remove('hidden');
  if (sideScreen) sideScreen.style.display = 'flex';
  const rp = document.getElementById('results-panel');
  if (rp) rp.style.display = 'none';
  renderQuestion();
}

// ========== الأحداث ==========
homeIcon.addEventListener('click', () => { if (autoTimeout) clearTimeout(autoTimeout); startScreen.classList.remove('hidden'); quizScreen.classList.add('hidden'); if (sideScreen) sideScreen.style.display = 'none'; certScreen.classList.add('hidden'); const rp = document.getElementById('results-panel'); if (rp) rp.style.display = 'none'; });
restartBtn.addEventListener('click', () => { if (autoTimeout) clearTimeout(autoTimeout); userAnswers = Array(questions.length).fill(null); current = 0; score = 0; answered = false; renderQuestion(); });
nextBtn.addEventListener('click', () => { if (autoTimeout) clearTimeout(autoTimeout); if (!answered) { nextBtn.classList.add('shake'); setTimeout(() => nextBtn.classList.remove('shake'), 300); const msg = document.createElement('div'); msg.textContent = '⚠️ أجب على السؤال أولاً'; msg.style.cssText = 'position:fixed; bottom:20px; left:50%; transform:translateX(-50%); background:#ef4444; color:white; padding:8px 16px; border-radius:20px; z-index:999;'; document.body.appendChild(msg); setTimeout(() => msg.remove(), 1500); return; } if (current < questions.length - 1) { current++; renderQuestion(); } else { showFinalResult(); } });
prevBtn.addEventListener('click', () => { if (autoTimeout) clearTimeout(autoTimeout); if (current === 0) return; current--; renderQuestion(); });
explanationTrigger.addEventListener('click', () => { if (explanationDiv && explanationDiv.style.display === 'block') hideExplanation(); else showExplanation(); });
document.querySelectorAll('.exam-item').forEach(btn => { btn.addEventListener('click', () => { const key = btn.dataset.exam; if (exams[key]) startExam(key); else alert('الامتحان غير متوفر'); }); });
document.querySelectorAll('.demo-btn').forEach(btn => { btn.addEventListener('click', () => { const pwd = prompt('كلمة المرور:'); if (pwd === btn.dataset.password) startExam(btn.dataset.exam); else alert('كلمة مرور خاطئة'); }); });

// ========== دعم اللمس ==========
let touchStartX = 0;
document.addEventListener('touchstart', (e) => { touchStartX = e.changedTouches[0].screenX; });
document.addEventListener('touchend', (e) => { const endX = e.changedTouches[0].screenX; if (endX < touchStartX - 50 && current < questions.length - 1 && answered) { current++; renderQuestion(); } else if (endX > touchStartX + 50 && current > 0) { current--; renderQuestion(); } });

// ========== الشهادة ==========
function fitNameFontSize(ctx, name, maxWidth) { let s = 86; while (s > 44) { ctx.font = `900 ${s}px Cairo`; if (ctx.measureText(name).width <= maxWidth) return s; s -= 4; } return s; }
function drawStudentName(ctx, name) { const centerX = 1988, baselineY = 872, maxW = 720; ctx.save(); ctx.direction = 'rtl'; ctx.textAlign = 'center'; ctx.textBaseline = 'alphabetic'; ctx.fillStyle = '#2f5689'; ctx.font = `900 ${fitNameFontSize(ctx, name, maxW)}px Cairo`; ctx.fillText(name, centerX, baselineY, maxW); ctx.restore(); }
downloadCertBtn.addEventListener('click', async () => {
  if (!window.jspdf) { alert('مكتبة PDF لم تحمل'); return; }
  const name = studentFullname.value.trim();
  if (!name) { alert('أدخل اسمك'); return; }
  downloadCertBtn.disabled = true; downloadCertBtn.textContent = 'جاري...';
  try {
    await document.fonts.ready;
    const src = typeof certificateTemplateDataUrl === 'string' ? certificateTemplateDataUrl : 'شهادة تقدير رمادي و أزرق.png';
    const img = await new Promise((res, rej) => { const i = new Image(); i.onload = () => res(i); i.onerror = rej; i.src = encodeURI(src); });
    const canvas = document.createElement('canvas'); canvas.width = img.width; canvas.height = img.height;
    const ctx = canvas.getContext('2d'); ctx.drawImage(img, 0, 0);
    drawStudentName(ctx, name);
    const pdf = new window.jspdf.jsPDF('landscape', 'mm', 'a4');
    pdf.addImage(canvas.toDataURL('image/png'), 'PNG', 0, 0, 297, 210);
    pdf.save(`certificate-${name}.pdf`);
  } catch(e) { alert('خطأ في الشهادة'); }
  finally { downloadCertBtn.disabled = false; downloadCertBtn.textContent = 'تحميل PDF'; }
});
startTotal.textContent = exams.web.questions.length;